sys_script_fix.script:
var writeAuditOOBACLList = ['308c2f231b5f6d10132a55392a4bcb1a'];
fixEmptyACL(writeAuditOOBACLList);

function fixEmptyACL(writeAuditOOBACLList) {
	gs.info(
		"*** Started deletion of ACL write audit customizations ***",
		"Empty_ACL_customization_deletion_FS"
	);

	new global.AccessControlUtils()
		.deleteCustomerUpdatesForAuditedEmptyACLs(
			writeAuditOOBACLList
		);

	gs.info(
		"*** Completed deletion of ACL write audit customizations ***",
		"Empty_ACL_customization_deletion_FS"
	);
}
